package com.hospital.management.validation;import com.hospital.management.model.DoctorScheduleForm;import java.time.*;import java.time.format.*;import java.util.Set;
/** Validates schedule windows and exact slot partitioning. */public class DoctorScheduleValidator{private static final Set<String>DAYS=Set.of("MONDAY","TUESDAY","WEDNESDAY","THURSDAY","FRIDAY","SATURDAY","SUNDAY");private static final DateTimeFormatter TIME=DateTimeFormatter.ofPattern("HH:mm").withResolverStyle(ResolverStyle.STRICT);public ValidationResult validate(DoctorScheduleForm f){ValidationResult r=new ValidationResult();if(f==null)return r;if(f.getDoctorId()==null||f.getDoctorId()<=0)r.addError("doctorId","Select a doctor");if(!DAYS.contains(f.getDayOfWeek()))r.addError("dayOfWeek","Select a valid day");LocalTime a=time(f.getStartTime(),"startTime",r),b=time(f.getEndTime(),"endTime",r);int slot=0;try{slot=Integer.parseInt(f.getSlotDurationMinutes());if(slot<5||slot>240)throw new Exception();}catch(Exception e){r.addError("slotDurationMinutes","Slot duration must be 5-240 minutes");}if(a!=null&&b!=null){long minutes=Duration.between(a,b).toMinutes();if(minutes<=0)r.addError("endTime","End time must be later than start time");else if(slot>0&&(slot>minutes||minutes%slot!=0))r.addError("slotDurationMinutes","Slot duration must divide the schedule window exactly");}return r;}private LocalTime time(String v,String k,ValidationResult r){try{return LocalTime.parse(v,TIME);}catch(Exception e){r.addError(k,"Enter time as HH:mm");return null;}}}
